(()=>{var e=document.querySelector(".menu-mobile"),t=document.querySelector(".page-header__menu");t.addEventListener("click",()=>{e.classList.contains("menu-mobile--close")?(e.classList.remove("menu-mobile--close"),e.classList.add("menu-mobile--active")):(e.classList.add("menu-mobile--close"),e.classList.remove("menu-mobile--active"))});var o=document.querySelector(".modal"),s=o.querySelector(".modal__overlay"),c=document.querySelector(".product__order");c.addEventListener("click",()=>{o.classList.add("modal--show")});s.addEventListener("click",()=>{o.classList.remove("modal--show")});})();
